mapper.select:
SELECT id, order_no, country_name, share_id, has_area_code, scheduled_time, status, CASE status WHEN 0 THEN '待发送' WHEN 1 THEN '发送中' WHEN 2 THEN '已完成' WHEN 3 THEN '发送失败' WHEN 4 THEN '已取消' ELSE '未知' END AS status_desc, success_count, fail_count, total_count, report_count, paid_count, cancel_count, create_time FROM share_order
AND order_no LIKE CONCAT('%', #{queryParams.orderNo}, '%')
AND country_id = #{queryParams.countryId}
AND share_id = #{queryParams.shareId}
AND status = #{queryParams.status}
AND create_by = #{currentUserId}
ORDER BY create_time DESC
